+func TestNewSearchCmd(t *testing.T) {
+	cmd := newSearchCmd()
+
+	if cmd.Use != "search <query>" {
+		t.Errorf("Use = %q; want %q", cmd.Use, "search <query>")
+	}
+	if cmd.Short == "" {
+		t.Error("Short description is empty")
+	}
+	if cmd.Long == "" {
+		t.Error("Long description is empty")
+	}
+	if cmd.Example == "" {
+		t.Error("Example is empty")
+	}
+}
